var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"제3 관리지구. 센트럴 클락 타워 옥상.","JPN":"第3管理地区。セントラルクロックタワー屋上。","ENG":"The 3rd Management District, Central Clock Tower Rooftop","TWN":"第3管理地區。中央時鐘塔的塔頂。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"나나하라 연합 본부.","JPN":"七原家連合本部。","ENG":"Nanahara Family Alliance Headquarters","TWN":"七原家族聯盟本部。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"건물 옥상에 이런 옛날 건물이 있다니…….","JPN":"建物の屋上にこんな古風な建物があるなんて……","ENG":"I didn’t expect to see such an old building on top of a tower...","TWN":"頂樓竟然有這種古代建築……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그런데, 이렇게 마음대로 들어와도 되는 거야?","JPN":"ところで、ここって勝手に入ってもいいのか？","ENG":"But is it really okay to just go in the building like this?","TWN":"不過就這樣進來沒問題嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"가문연합 소속이라면 말이야.","JPN":"連合所属なら平気だ。","ENG":"It’s okay if you belong to the Family Alliance.","TWN":"是家族聯盟的成員就沒問題。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"……뭐, 나도 여기 다시 올 생각은 없었지만.","JPN":"……まあ、オレもここに戻ってくるつもりはなかったが。","ENG":"I never thought I would come back to this place, though.","TWN":"……雖然我也沒想過會再回來這裡。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_QM","text":{"KOREA":"오래 기다렸습니다. 카토리 님. 일행도 한 분 계시는군요.","JPN":"長らくお待ちしておりました、香取様。お連れ様がいらっしゃるのですね。","ENG":"We’ve been waiting for you, Mr. Katori. I see you have company.","TWN":"香取，我等你很久了。你還帶了一個人嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"카토리… 라고?","JPN":"香取……って？","ENG":"Katori?","TWN":"香取… ？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"오오가미라니까, 장로님!","JPN":"オレは大神様だぞ、長老！","ENG":"Elder, it’s Ogami!","TWN":"我叫大神啦，長老！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_QM","text":{"KOREA":"바깥에서 어떤 이름을 쓰건 상관 없으나, 적어도 이곳에선 전통을 따르시지요.","JPN":"外でどのような名前を使っても構いませんが、\\n少なくともこちらでは伝統に従っていただければ。","ENG":"You may use any name you choose when you’re outside, but while you’re here, you must follow traditions.","TWN":"你在外面要用什麼名字都沒關係，但起碼在這裡要尊重傳統。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_QM","text":{"KOREA":"곧 연합의 회동이 시작됩니다. 가문연합의 일원에 걸맞은 예복을 갖추세요.","JPN":"まもなく連合の会合が始まります。\\n連合の一員にふさわしい礼服にお着替えくださいませ。","ENG":"The Alliance meeting is about to start. Please dress accordingly.","TWN":"聯盟的聚會即將開始，請換上符合家族聯盟成員身分的服裝。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하, 예복 같은 거 필요없어. 영감들한테 예절 차리러 온 적 없으니까.","JPN":"ハッ、礼服なんていらねえ。\\nジジイたちに挨拶しに来たわけじゃないからな。","ENG":"Hah, I don’t have to dress up. I’m not here to play a polite young man before the elders.","TWN":"哈，不需要換什麼衣服啦，對那些老傢伙們我從來沒有講究過禮節。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"미리 말해 두는데 난 여기 안 남아 있을 거야. 일을 마치는 대로 돌아갈 거다.","JPN":"先に言っておくが、オレはここに残るつもりはない。用件が終わったらさっさと帰る。","ENG":"For your information, I won’t be staying here. I’m going back as soon as my business here is done.","TWN":"我醜話先說在前頭，我沒有要留在這裡，等事情一辦完就會立刻走人。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_QM","text":{"KOREA":"……그렇다면, 당신의 용무는 일행 분과 관련된 것인가요?","JPN":"……それでは、そなたのご用件はお連れ様と関連したものでしょうか？","ENG":"And that business concerns your company here?","TWN":"……所以你要辦的事情和那個人有關嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그냥 일행이 아냐. 내 친구지.","JPN":"ただの連れじゃない。オレの友達だ。","ENG":"He’s not just my company, he’s my friend.","TWN":"他不是那個人，他是我朋友。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"처음 뵙겠습니다. 나유카 미나토라고 합니다.","JPN":"初めまして、奈由香湊と申します。","ENG":"Nice to meet you. I’m Nayuka Minato.","TWN":"初次見面你好，我叫南裕夏。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_QM","text":{"KOREA":"나유카…….","JPN":"奈由香……","ENG":"Nayuka...","TWN":"南裕夏……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_QM","text":{"KOREA":"당주님께서 한동안 부재 중이시더니, 그리된 것이었군요.","JPN":"当主はしばらくご不在でしたが、そういうわけだったのですね。","ENG":"I haven’t seen Lady Nanahara for a while; now I see what happened.","TWN":"堂主一段時間不在，原來是因為這樣。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_QM","text":{"KOREA":"나나하라 사요라고 합니다. 나유카 님.","JPN":"七原小夜と申します、奈由香様。","ENG":"I am Nanahara Sayo, Sir Minato Nayuka.","TWN":"南裕夏你好，我叫七原小夜。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"방계라곤 해도 연합의 일원. 원한다면 회동에 참석하셔도 좋습니다.","JPN":"傍系とはいえ連合の一員。お望みでしたら、会合に参加いただいても構いません。","ENG":"Though you are from the collateral family, you’re one of us nevertheless. You may join the meeting if you wish.","TWN":"旁系也算是聯盟的成員，你願意的話也可以參加聚會。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그럼 곧 다시 뵙도록 하지요.","JPN":"それでは、またお会いしましょう。","ENG":"I’ll see you later, then.","TWN":"那我們就稍後再見囉。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"신기하다. 가문연합 사람들은 전부 저런 복장인가 보네…….","JPN":"不思議だな。家門連合の人たちはみんなあんな服装なんだ……","ENG":"Wow. Do all the Family Alliance dress up like that?","TWN":"真奇妙，看來家族聯盟的人都要穿成那樣……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"글쎄. 네가 본 두 명이 제일 요란하다고만 해 두지.","JPN":"さあな。お前が見た二人が一番ド派手ってことだけ言っておこう。","ENG":"Not really, just the two that you’ve met.","TWN":"可能吧，不過你見過的那兩個人應該算是最厲害的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그런데 마사키, 방금 저 사람을 장로라고 불렀지? 어떤 사람이야?","JPN":"ところで雅紀、さっきの人を長老と呼んでたよな？　どんな人？","ENG":"Masaki, you called her Elder. Who is she?","TWN":"雅紀，你剛剛是叫她長老嗎？她是誰？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"말 그대로야. 가문 연합을 통틀어 가장 늙은 사람.","JPN":"言葉どおりだ。家門連合の中で一番のご老体ってことだ。","ENG":"Literally, she’s the oldest one in the Family Alliance.","TWN":"她是整個家族聯盟中最年長的，所以是長老囉！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"신기하네. 그렇게 나이가 많아 보이진 않던데.","JPN":"不思議だね。そこまで年を取ってそうには見えなかったけど。","ENG":"That’s curious. She didn’t seem so old.","TWN":"真的假的？她看起來年紀沒有很大欸？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"저렇게 보여도 실제론 할머니라고. 얼굴을 가리고 다녀서 잘 몰랐겠지만.","JPN":"ああ見えても、実際はおばあちゃんだぞ。顔を隠しているからよくわからないだろうが。","ENG":"She’s actually a granny. You probably didn’t notice because of the mask.","TWN":"只是看起來啦，她實際上是個老奶奶。可能是因為她都遮著臉吧，所以看不清楚。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Really?","TWN":"嗯？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그럼 그 치나츠라는 여자애도, 사실 나이가 엄청 많다던가?","JPN":"じゃあ、あの千夏って子も、実はすごい年上だとか？","ENG":"Then that Chinatsu girl is actually old, too?","TWN":"所以那個叫千夏的女生，其實年紀也很大嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"장로는 단지 연합의 최고령자로서 존중받고 있을 뿐이야. 치나츠는 당주라고.","JPN":"長老はただ連合の最高齢者として尊重されてるだけだ。\\n千夏は当主だぞ。","ENG":"That woman is an elder, people respect her for her age. But Chinatsu is the family leader.","TWN":"長老只是因為最年長，所以受到大家的尊重，但千夏是堂主。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"다른 거야?","JPN":"違うの？","ENG":"They are different?","TWN":"不一樣嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"완전히 다르지. 나나하라의 당주가 되려면 바람의 목소리란 걸 들을 수 있어야 하거든.","JPN":"全然違う。七原家の当主になるには風の声ってのを聞けないとダメなんだ。","ENG":"Absolutely. To be the family leader of Nanaharas, you should be able to hear the voice of wind.","TWN":"當然不一樣。要想成爲七原的堂主，必須能夠聽到風的聲音。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"당주가 그 힘으로 앞날을 예언하면, 연합은 미리 대비하는 거지.","JPN":"当主がその力で未来を予言したら、\\n連合はそれに対して事前に備えておくことができる。","ENG":"When the leader tells a prophecy using the power, the Alliance prepares for what’s coming.","TWN":"堂主會用那股力量來發預言，聯盟則是要事先做好預備。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"예언? 그게 사실이라면 굉장한 능력 아냐?","JPN":"予言？　それが事実ならとんでもない能力なんじゃないか？","ENG":"Prophecy? That’s amazing.","TWN":"預言？如果真的能預知未來，那不是特異功能嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"굉장하긴 한데, 듣기로는 세대가 지날수록 그 힘도 점점 약해지고 있다나 봐.","JPN":"とんでもないものではあるが、聞いた話だと\\n世代を経るにつれてその力もだんだん弱くなっているらしい。","ENG":"It is amazing, but I heard the power is waning as generations pass.","TWN":"是很厲害沒錯，但我聽說經過幾個世代後，那股力量似乎也越來越薄弱了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그래서인지 가끔은…","JPN":"そのせいか、たまに……","ENG":"And sometimes...","TWN":"或許就是因為這樣…"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그 예언이 틀리는 일도 있고 말이지.","JPN":"その予言が外れることもあるしな。","ENG":"The leader gives you an incorrect prophecy.","TWN":"預言也有出錯的時候。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"사연이 복잡한 곳 같아 보이는데, 마사키는 꽤 많이 알고 있구나.","JPN":"複雑な事情がありそうだけど、雅紀は色々詳しいんだね。","ENG":"Sounds complicated, but you seem to know them pretty well.","TWN":"感覺這個地方很複雜呢，不過你倒是知道挺多的嘛！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"지금까지 말해주지 않아서 실망했냐?","JPN":"今まで黙っていたことに失望したか？","ENG":"Are you disappointed that I didn’t tell you all these things before?","TWN":"我之前都沒跟你說這些，你很失望嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아니.","JPN":"いや。","ENG":"No.","TWN":"不。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그전까진 몰라도 됐으니까.","JPN":"今までは知らなくてもいい話だったから。","ENG":"I didn’t need to know them back then.","TWN":"之前不知道也無所謂。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"너도 내가 알 필요 없는 사실이라서 말하지 않았을 뿐이잖아?","JPN":"お前だって、僕が知る必要はないと思ったから言わなかっただけだろ？","ENG":"You kept it to yourself because it wasn't a need-to-know basis, right?","TWN":"你只是覺得我不需要知道才沒跟我說的吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"연합이란 곳은 아무래도 내가 바라던 평범한 일상과는 한참 동떨어진 곳 같으니까.","JPN":"連合ってのは、どうやら僕が望んでいた平凡な日常とはかなりかけ離れたところみたいだし。","ENG":"It’s obvious that this Alliance is far from the ordinary life that I wished for anyways.","TWN":"畢竟聯盟這個地方，似乎和我想要的平凡生活相去甚遠。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"미나토…….","JPN":"湊……","ENG":"Minato...","TWN":"南裕夏……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"훗, 역시 넌 오오가미 흑막조장의 오른팔이 될 자격이 충분하다.","JPN":"フッ、やっぱりお前は大神黒幕組長の右腕にふさわしいぜ。","ENG":"Hah, you truly deserve to be the Ogami's Shadow Group’s right-hand man.","TWN":"呵，你果然有資格成為黑幕組組長的心腹！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"그건 안 됩니다!","JPN":"それはいけません！","ENG":"You can’t!","TWN":"那可不行！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Yes?","TWN":"嗯？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"이 목소리는……. 그 자매들인가?","JPN":"この声は……あの姉妹か？","ENG":"This voice... It must be the sisters.","TWN":"這個聲音是……那對姊妹嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"누가 싸우는 것 같은데? 말려야 하는 거 아냐?","JPN":"誰かがケンカしてるみたいだけど。止めたほうがいいんじゃない？","ENG":"Are they arguing? Maybe we should stop them?","TWN":"好像有人在吵架？要去勸架嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하지 마. 집안 싸움에 괜히 끼어들었다간 네 입장만 복잡해져.","JPN":"やめとけ。よその家の争いに首を突っ込むと、後で困るのはお前だぞ。","ENG":"No. That’s a family dispute, leave them be.","TWN":"不用啦，清官難斷家務事，你只會弄得裡外不是人。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"자, 어서 본당으로 가자. 늦으면 영감들이 한 소리 할 테니까.","JPN":"さあ、さっさと本堂に行こう。遅れたらジジイたちがうるさいだろうしな。","ENG":"We have to go to the main temple. The oldies will get mad if we’re late.","TWN":"走吧，我們快去正殿吧！遲到的話老傢伙們會碎念的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"먼저 가, 마사키.","JPN":"先に行ってて、雅紀。","ENG":"You go first, Masaki.","TWN":"雅紀，你先過去。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"야! 미나토!","JPN":"おい！　湊！","ENG":"Hey, Minato!","TWN":"喂！南裕夏！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"쳇……. 오지랖 넓은 자식…….","JPN":"まったく……お人好しなやつだ……","ENG":"Aww, he’s so nosy...","TWN":"嗟… 有夠雞婆的…"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"호위인 저를 두고 혼자 연합을 나가신 것까지는 이해해 드릴 수 있습니다.","JPN":"護衛の私を残して、一人で連合本部の外へ出られたことまでは理解できます。","ENG":"I let you off the hook when you went outside without me guarding you.","TWN":"我可以明白堂主為何要獨自出門不帶著我。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만 갑자기 의식을 치르시겠다니, 어째서 마음을 바꾸셨습니까?","JPN":"しかし、急に儀式を行うなんて、いったいどうしてなのですか？","ENG":"But now you’re going to perform the ritual? Why did you change your mind so suddenly?","TWN":"但堂主為何突然又說要舉行儀式，爲什麼改變心意？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……과거의 실수를 바로잡기 위해서야. 같은 방법으로는 과오를 되풀이할 뿐이니까.","JPN":"……過去の過ちを正すためよ。同じ方法では過ちを繰り返すだけだから。","ENG":"I want to correct my past mistake. Using the same method will only repeat the error we made.","TWN":"……因為我想導正過去的錯誤，用同樣的方法只會重蹈覆轍而已。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"재고해 주십시오. 호위 무사로서, 아니, 가문의 일원으로서 납득할 수 없습니다.","JPN":"考え直してください。護衛として、いえ、家門の一員として納得できません。","ENG":"Please reconsider. As your bodyguard and a member of the family, I can’t accept it.","TWN":"請堂主三思！身為護衛武士，不，是身為家族的一員，我無法接受。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그리고 이 검은……. 당주님을 지키기 위해 든 것입니다.","JPN":"そしてこの刀は……当主を守るために手にしたものです。","ENG":"I wield my sword... only to protect you.","TWN":"還有……我手裡的這把劍，是為守護堂主而存在。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"나는 나나하라의 당주로서, 모두에게 최선이 되는 결정을 내릴 의무가 있다.","JPN":"私は七原家の当主として、みんなにとって最善の決断を下す義務がある。","ENG":"As the leader of the Nanahara family, I’m obligated to make a decision that will benefit everyone.","TWN":"我身為七原的堂主，有義務作出對大家最好的決定。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"너도 내 호위 무사로서, 사사로운 감정에 엮이지 말거라.","JPN":"千冬も私の護衛として、私情に流されないでほしい。","ENG":"And you, as my bodyguard, should not cling to personal emotions.","TWN":"而你是我的護衛武士，不要公私不分。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"Um...","TWN":"可是……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……알겠습니다. 듣는 귀가 있으니 말을 아끼죠.","JPN":"……承知しました。ここは他の者もいるので、言葉を慎みます。","ENG":"... I understand. There’s someone listening to us, so I won’t say any further.","TWN":"……好吧，就先說到這裡，畢竟隔牆有耳。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"잠시 물러나 있겠습니다. 필요하실 때는 언제든 불러 주시길.","JPN":"しばらく下がります。必要な時はいつでもお呼びください。","ENG":"I’ll leave for now. Please call me when you need me.","TWN":"我先退下，有需要時請隨時呼叫我。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"나오셔도 좋습니다. 미나토 님.","JPN":"出てきて大丈夫ですよ、湊様。","ENG":"You may come forward, Mr. Nayuka.","TWN":"出來吧，南裕夏。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아, 하하……. 미안. 의도치 않게 조금 듣게 됐어.","JPN":"あ、ははは……ごめん。わざとじゃないけど少し聞いちゃった。","ENG":"Oh, hah hah... I’m sorry. I didn’t mean to overhear.","TWN":"呵呵……不好意思，我不是故意要偷聽的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"본의 아니게 좋지 않은 모습을 보여 드렸네요.","JPN":"不本意ながら、お恥ずかしい所をお見せしてしまいましたね。","ENG":"I am sorry you had to see that.","TWN":"竟然讓你看到這種場面。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이곳까지 와 주신 것에 대해 감사드려요.","JPN":"ここまで来てくださったことに感謝申し上げます。","ENG":"And I thank you for visiting us here.","TWN":"謝謝你願意過來。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"너무 딱딱하게 대하지 마.","JPN":"そんなにかしこまらなくていいよ。","ENG":"Don’t be so formal.","TWN":"不用這麼客氣。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"지금은 위험한 상황이잖아. 서로 힘을 모으는 게 당연하지.","JPN":"今は危険な状況だろ。お互い力を合わせるのが当然だよ。","ENG":"We’re in a dire situation. It’s only natural that we help each other.","TWN":"現在是非常時刻，彼此幫助也是理所當然的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……그렇군요. 지극히 옳은 말씀이십니다.","JPN":"……そうですね。至極ごもっともなお言葉です。","ENG":"... Yes. You’re right.","TWN":"……沒錯，你說得非常正確。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"마사키 님과는 함께 오지 않으셨나요?","JPN":"雅紀様と一緒にいらしたのではないのでしょうか？","ENG":"Is Mr. Katori not with you?","TWN":"雅紀沒和你一起來嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그게, 실은 신경 쓰지 말라는 걸 뿌리치고 나 혼자 와 버렸어. 돌아가면 사과해야겠네.","JPN":"それが、余計なことに首を突っ込むなって言われたのを無視して\\n僕一人で来ちゃったんだ。戻ったら謝らないと。","ENG":"Well, Masaki told me not to interfere, but I came here anyway. I’ll have to apologize when I see him again.","TWN":"這個嘛，我扔下他自己跑來的，回去要跟他謝罪囉！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"치나츠도 마사키랑 연합에서 알고 지내던 사이야?","JPN":"千夏は雅紀と連合で知り合ったの？","ENG":"You know Masaki because of the Alliance?","TWN":"千夏和雅紀是在聯盟裡認識的嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"마사키 님은…… 연합의 일원이지만, 직접 저희와 함께 행동하진 않습니다.","JPN":"雅紀様は……連合の一員ではありますが、私たちと行動を共にすることはございません。","ENG":"Mr. Katori is a member of the Alliance... But he doesn’t work with us.","TWN":"雅紀他……雖然是聯盟的成員，但他不會和我們一起行動。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그러던 중 연락이 닿은 것도 최근의 일이었어요.","JPN":"連絡がついたのもつい最近のことです。","ENG":"It’s only recent that we got in touch with each other.","TWN":"我們也是最近才有聯絡。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"하하, 여기서도 그 흑막조 컨셉은 충실한가 보네.","JPN":"ハハ、ここでもあの黒幕組ってキャラは守ってるんだな。","ENG":"Hah hah, I see he’s playing that Shadow Group thing here, too.","TWN":"哈哈，這裡的風格跟黑幕組很像呢！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네? 흑막조라는 건…… 무엇인가요?","JPN":"はい？　黒幕組というのは……何でしょうか？","ENG":"Shadow Group? May I ask what it is?","TWN":"嗯？黑幕組……是什麼？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아, 마사키가 운영하는 조직 이름이야.","JPN":"ああ、雅紀が運営する組織の名前だよ。","ENG":"Oh, it’s the name of an organization that Masaki runs.","TWN":"喔，是雅紀經營的組織名字。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"연합을 따르지 않는 고독한 어둠의 존재…… 라고 했던가?","JPN":"連合に従わない孤独な闇の存在……だったかな？","ENG":"He said something like... a lonely secret organization that doesn’t follow the Alliance’s instructions?","TWN":"不順服聯盟的孤獨的黑暗存在… 好像是這樣吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"뭐, 그냥 우리끼리 재미로 하는 농담이니까 너무 진지하게 받아들일 필욘 없어.","JPN":"まあ、僕たちの面白半分の冗談だから、\\nあまり真剣に受け止める必要はないよ。","ENG":"It’s just a joke, so don’t take it too seriously.","TWN":"喔～這只是我們之間的玩笑話啦，你不用太認真。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"난 지금껏 그 녀석이 말하던 연합이란 게 실제로 있는지도 몰랐거든.","JPN":"僕は今まであいつが言ってた連合というのが実際にあることすら知らなかったからね。","ENG":"To be honest, I didn’t even know the Alliance was real.","TWN":"我到現在都還搞不清楚，他所謂的聯盟到底存不存在咧！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"치나츠? 괜찮아?","JPN":"千夏？　大丈夫？","ENG":"Chinatsu? Are you okay?","TWN":"千夏？還好嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네, 조금 안심했을 뿐입니다.","JPN":"はい、少し安心しただけです。","ENG":"Yes, it’s just that I’m a bit relieved.","TWN":"我沒事，只是有點安心而已。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"바깥에서 마사키 님은… 제가 걱정하던 것보다 잘 지내고 계신 것 같군요.","JPN":"外の世界で雅紀様は……私が心配していたよりも元気に過ごしていらっしゃったようですね。","ENG":"It’s good to know that Mr. Katori is faring well outside; I was concerned about him.","TWN":"我本來還很擔心雅紀一個人在外面…幸好他過得很好。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그래?","JPN":"そう？","ENG":"Really?","TWN":"是喔？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"당주라고 해서 딱딱하고 엄격할 줄 알았는데…","JPN":"当主というから、とても堅苦しい性格だと思ってたけど……","ENG":"I thought you would be a stern person as you are the family leader…","TWN":"我還以爲堂主都很食古不化又嚴格…"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"치나츠는 상냥한 사람이구나.","JPN":"千夏は優しい人なんだね。","ENG":"But you’re very kind.","TWN":"但是你很善良呢！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"마사키 님이 그렇게 된 것엔 제 책임이 크니까요.","JPN":"雅紀様がああなってしまったのは、私の責任が大きいですから。","ENG":"I’m the main reason for what happened to Mr. Katori.","TWN":"畢竟雅紀會變成那樣，我必須必須負很大的責任。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇기 때문에, 저는 그 책임을 져야만 해요.","JPN":"だからこそ、私はその責任を負わなければなりません。","ENG":"Therefore, I should be responsible for the consequences.","TWN":"所以，我必須負起責任。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"책임이라니?","JPN":"責任って？","ENG":"Responsible?","TWN":"什麼責任？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"으음, 혹시 마사키의 중2병에 결정적인 원인을 제공하기라도 한 거야?","JPN":"うーん、もしかして雅紀の中二病の決定的な原因を作ったとか？","ENG":"What, you're the one who makes him edgelord?","TWN":"嗯，難道是雅紀會得中二病，是因為你的關係嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……미나토 님.","JPN":"……湊様。","ENG":"Mr. Nayuka…","TWN":"……南裕夏。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"전 나나하라의 당주로서 책임을 지고, 빠른 시일 안에 이 사태를 해결할 계획입니다.","JPN":"私は七原家の当主として責任を取り、早急にこの事態を解決するつもりです。","ENG":"As the leader of the Nanahara family, I am willing to solve this situation in the speediest manner possible.","TWN":"我身為七原的堂主，會負起責任儘快解決這件事的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그러기 위해선 미나토 님의 도움이 필요해요.","JPN":"そのためには湊様の助けが必要です。","ENG":"That’s why I need your help.","TWN":"因此，我需要你的幫助。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"절 도와주실 수 있으신가요?","JPN":"私に力を貸していただけませんか？","ENG":"Will you help me?","TWN":"你可以幫我嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그거라면 걱정 마.","JPN":"それなら心配しないで。","ENG":"Don't worry about that.","TWN":"放心吧！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"나도 하루 빨리 일상을 되찾고 싶거든.","JPN":"僕だって一日も早く日常を取り戻したいんだ。","ENG":"I also want to go back to my ordinary life as soon as I can, you know.","TWN":"我也想儘快恢復平凡的生活。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};